import {AsyncStorage} from 'react-native';

// Function to generate a random token
const generateToken = () => {
    return Math.random().toString(36).substring(7);
};

// Async function to save a new token in the device storage
export const createNewSessionToken = async () => {
    let newToken;
    try {
        // Generate a new token
        newToken = generateToken();
        // Save it in the device storage (AsyncStorage) under a key of 'sessionToken'
        await AsyncStorage.setItem('sessionToken', newToken);
    } catch(error){
        console.log("Error saving session token:", error);
    } 
};

// Function to retrieve a stored session token
export const getSessionToken = async () => {
    try{
        // Get the 'sessionToken' from AsyncStorage
        return await AsyncStorage.getItem('sessionToken');
    } catch(error){
        console.log("Error retrieving session token:", error);
    } 
};